{
  "title": "`LEFT JOIN` की मूल बातें",
  "group": "SQL जॉइन्स",
  "options": [
    {
      "text": "हर मिलान वाली पंक्ति के लिए एक पंक्ति लौटाता है, बिना मिलान वाली पंक्तियों को नज़रअंदाज़ करता है"
    },
    {
      "text": "बाईं तालिका की सभी पंक्तियाँ लौटाता है, साथ ही दाईं तालिका की मिलान वाली पंक्तियाँ भी"
    },
    {
      "text": "सभी मिलान वाली या बिना मिलान वाली पंक्तियाँ लौटाता है, जहाँ `NULL` का मतलब है कोई मिलान नहीं"
    },
    {
      "text": "दाईं तालिका की सभी पंक्तियाँ लौटाता है, साथ ही बाईं तालिका की मिलान वाली पंक्तियाँ भी"
    }
  ],
  "questionProse": [
    "SQL में `LEFT JOIN` असल में क्या करता है?"
  ],
  "explanationProse": [
    "`LEFT JOIN` बाईं तालिका की सभी पंक्तियाँ लौटाता है और दाईं तालिका से केवल मिलान वाली पंक्तियाँ जोड़ता है। जहाँ दाईं तरफ कोई मिलान नहीं मिलता, वहाँ `NULL` आ जाता है। सीधा और स्पष्ट।"
  ]
}
